   124→		return kubeClient.CoreV1().ConfigMaps(namespace).Get(context.TODO(), name, opts)
   125→	}
   126→	configMapStore := manager.NewObjectStore(getConfigMap, clock.RealClock{}, getTTL, defaultTTL)
