    51→func (strategy) NamespaceScoped() bool {
    52→	return true
    53→}
    54→
    55→func (strategy) PrepareForCreate(ctx context.Context, obj runtime.Object) {
    56→	secret := obj.(*api.Secret)
    57→	dropDisabledFields(secret, nil)
    58→}
    59→
    60→func (strategy) Validate(ctx context.Context, obj runtime.Object) field.ErrorList {
    61→	return validation.ValidateSecret(obj.(*api.Secret))
    62→}
